import React, { Component } from 'react';
import './index.css';

class NavBar extends Component {
  render() {
    return (
      <nav className="navbar navbar-expand-lg navbar-light transparent-navbar shadow-sm">
        <div className="container-fluid px-4">
          {/* Logo */}
          <a className="navbar-brand fw-bold text-white" href="#home">
            <i className="bi bi-heart-fill text-danger me-2"></i>
            LifeGift
          </a>

          {/* Toggle for mobile */}
          <button className="navbar-toggler" type="button" data-bs-toggle="collapse" data-bs-target="#navbarNav">
            <span className="navbar-toggler-icon"></span>
          </button>

          {/* Nav items */}
          <div className="collapse navbar-collapse justify-content-end" id="navbarNav">
            <ul className="navbar-nav align-items-center">
              <li className="nav-item"><a className="nav-link text-white mx-2" href="#profile">Profile</a></li>
              <li className="nav-item"><a className="nav-link text-white mx-2" href="#donation">Donation</a></li>
              <li className="nav-item"><a className="nav-link text-white mx-2" href="#collection">Collection</a></li>
              <li className="nav-item"><a className="nav-link text-white mx-2" href="#feature">Feature</a></li>
              <li className="nav-item"><a className="nav-link text-white mx-2" href="#authority">Authority</a></li>
              <li className="nav-item">
                <button className="btn btn-outline-light btn-sm ms-3">
                  <i className="bi bi-box-arrow-right me-1"></i> Logout
                </button>
              </li>
            </ul>
          </div>
        </div>
      </nav>
    );
  }
}

export default NavBar;
